# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import Counter
import numpy as np
import pickle
from sklearn.ensemble import RandomForestClassifier
from sklearn.preprocessing import LabelEncoder
import os

app = Flask(__name__)

# Store annotations
annotations = {}
model = None
label_encoder = LabelEncoder()

@app.route('/annotate', methods=['POST'])
def annotate():
    data = request.get_json()
    image_id = data['image_id']
    label = data['label']
    annotator_id = data['annotator_id']
    
    if image_id not in annotations:
        annotations[image_id] = []
    
    annotations[image_id].append({
        'label': label,
        'annotator_id': annotator_id
    })
    
    return jsonify({'status': 'success'})

@app.route('/aggregate', methods=['POST'])
def aggregate():
    data = request.get_json()
    image_id = data['image_id']
    
    if image_id not in annotations:
        return jsonify({'error': 'No annotations found'}), 404
    
    labels = [ann['label'] for ann in annotations[image_id]]
    aggregated_label = Counter(labels).most_common(1)[0][0]
    
    return jsonify({'image_id': image_id, 'aggregated_label': aggregated_label})

@app.route('/train', methods=['POST'])
def train():
    global model, label_encoder
    
    # Collect all labeled data
    all_labels = []
    all_features = []
    
    for image_id, annots in annotations.items():
        labels = [ann['label'] for ann in annots]
        aggregated_label = Counter(labels).most_common(1)[0][0]
        all_labels.append(aggregated_label)
        
        # Dummy features - in practice, extract actual image features
        all_features.append([hash(image_id) % 1000])
    
    if not all_labels:
        return jsonify({'error': 'No data to train'}), 400
    
    # Encode labels
    encoded_labels = label_encoder.fit_transform(all_labels)
    
    # Train model
    model = RandomForestClassifier(n_estimators=100, random_state=42)
    model.fit(all_features, encoded_labels)
    
    return jsonify({'status': 'model trained successfully'})

@app.route('/predict', methods=['POST'])
def predict():
    data = request.get_json()
    image_features = data['features']
    
    if model is None:
        return jsonify({'error': 'Model not trained'}), 400
    
    prediction = model.predict([image_features])
    predicted_label = label_encoder.inverse_transform(prediction)[0]
    
    return jsonify({'predicted_label': predicted_label})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)